import { createContext, useContext, useState, useMemo } from 'react';

const ThemeContext = createContext(null);

export function ThemeProvider({ children }) {
  const [theme, setTheme] = useState('light');
  const value = useMemo(() => ({ theme, setTheme }), [theme]);
  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

export function useTheme() {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error('useTheme: wrap with ThemeProvider');
  return ctx;
}

// Consumer that reads the value:
function Article() {
  const { theme } = useTheme();
  return <article className={theme}>...</article>;
}

// Consumer that updates the value:
function ThemeToggle() {
  const { theme, setTheme } = useTheme();
  return (
    <button onClick={() => setTheme(t => t === 'light' ? 'dark' : 'light')}>
      Switch to {theme === 'light' ? 'dark' : 'light'}
    </button>
  );
}

// Safe: setTheme from context never becomes stale
function ThemeToggle() {
  const { setTheme } = useTheme();

  // setTheme is the same function reference every render
  // — safe to use in event handlers, effects, or callbacks
  const toggle = useCallback(() => {
    setTheme(t => t === 'light' ? 'dark' : 'light');
  }, [setTheme]); // setTheme is stable, so toggle is stable too

  return <button onClick={toggle}>Toggle</button>;
}

// Toggle (depends on current value — use functional form)
const { setTheme } = useTheme();
setTheme(current => current === 'light' ? 'dark' : 'light');

// Append to an array in context
const { setTags } = useTags();
setTags(prev => [...prev, newTag]);

// Increment a counter
const { setCount } = useCount();
setCount(c => c + 1);

const AppContext = createContext(null);

function appReducer(state, action) {
  switch (action.type) {
    case 'SET_USER':   return { ...state, user: action.user };
    case 'SET_THEME':  return { ...state, theme: action.theme };
    case 'TOGGLE_SIDEBAR': return { ...state, sidebarOpen: !state.sidebarOpen };
    default: throw new Error(`Unknown action: ${action.type}`);
  }
}

export function AppProvider({ children }) {
  const [state, dispatch] = useReducer(appReducer, {
    user: null,
    theme: 'light',
    sidebarOpen: false,
  });

  const value = useMemo(() => ({ state, dispatch }), [state]);
  return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
}

// Child dispatches an action to update context:
function LoginButton({ user }) {
  const { dispatch } = useContext(AppContext);
  return (
    <button onClick={() => dispatch({ type: 'SET_USER', user })}>
      Log in
    </button>
  );
}

// Another child reads the resulting state:
function Greeting() {
  const { state } = useContext(AppContext);
  return <p>Hello, {state.user?.name ?? 'Guest'}</p>;
}

const AppStateContext    = createContext(null);
const AppDispatchContext  = createContext(null);

export function AppProvider({ children }) {
  const [state, dispatch] = useReducer(appReducer, initialState);
  return (
    <AppDispatchContext.Provider value={dispatch}>
      <AppStateContext.Provider value={state}>
        {children}
      </AppStateContext.Provider>
    </AppDispatchContext.Provider>
  );
}

// Hook for state (re-renders on state changes):
export const useAppState    = () => useContext(AppStateContext);
// Hook for dispatch (never re-renders — dispatch is stable):
export const useAppDispatch = () => useContext(AppDispatchContext);

function Provider({ children }) {
  const [user, setUser] = useState(null);
  const [theme, setTheme] = useState('light');

  // ✗ Without useMemo: new object each render → all consumers re-render
  // return <Ctx.Provider value={{ user, setUser, theme, setTheme }}>{children}</Ctx.Provider>;

  // ✓ With useMemo: new object only when user or theme changes
  const value = useMemo(
    () => ({ user, setUser, theme, setTheme }),
    [user, theme]
    // setUser and setTheme are stable — not needed in deps
  );
  return <Ctx.Provider value={value}>{children}</Ctx.Provider>;
}

// DevTools flow to debug a context update:
// 1. Open React DevTools → Components tab
// 2. Click ThemeProvider in the tree
// 3. Inspect Hooks → State: ['light', f]
// 4. Click ThemeToggle in your app UI
// 5. State changes to ['dark', f]
// 6. Click any consumer (e.g. Article) — Context: { theme: 'dark', setTheme: f }

function ResetAll() {
  const { setTheme } = useTheme();
  const { setUser }  = useAuth();

  function handleReset() {
    setTheme('light'); // batched
    setUser(null);     // batched
    // React batches both: one re-render at the end of the event handler
  }

  return <button onClick={handleReset}>Reset</button>;
}

function LikeButton({ postId }) {
  const { posts, dispatch } = useContext(PostsContext);
  const post = posts.find(p => p.id === postId);

  async function handleLike() {
    // Optimistic update:
    dispatch({ type: 'LIKE_POST', id: postId });

    try {
      await api.likePost(postId);
    } catch {
      // Roll back on failure:
      dispatch({ type: 'UNLIKE_POST', id: postId });
    }
  }

  return (
    <button onClick={handleLike}>
      {post?.liked ? '♥ Liked' : '♡ Like'}
    </button>
  );
}

// Anti-pattern: global context for local UI state
const GlobalCtx = createContext(null);
// Storing 'isDropdownOpen' here causes every consumer to re-render
// when a dropdown opens — even unrelated components.

// Better: keep dropdown state local to the component that owns it
function Dropdown() {
  const [open, setOpen] = useState(false); // local — no context needed
  return <div>{open && <Menu />}</div>;
}

const CartContext = createContext(null);

function cartReducer(state, action) {
  switch (action.type) {
    case 'ADD_ITEM': {
      const existing = state.items.find(i => i.id === action.item.id);
      if (existing) {
        return {
          ...state,
          items: state.items.map(i =>
            i.id === action.item.id ? { ...i, qty: i.qty + 1 } : i
          ),
        };
      }
      return { ...state, items: [...state.items, { ...action.item, qty: 1 }] };
    }
    case 'REMOVE_ITEM':
      return { ...state, items: state.items.filter(i => i.id !== action.id) };
    case 'CLEAR':
      return { ...state, items: [] };
    default:
      throw new Error(`Unknown cart action: ${action.type}`);
  }
}

export function CartProvider({ children }) {
  const [state, dispatch] = useReducer(cartReducer, { items: [] });
  const value = useMemo(() => ({ cart: state, dispatch }), [state]);
  return <CartContext.Provider value={value}>{children}</CartContext.Provider>;
}

export function useCart() {
  const ctx = useContext(CartContext);
  if (!ctx) throw new Error('useCart: wrap with CartProvider');
  return ctx;
}

// ProductCard — adds items:
function ProductCard({ product }) {
  const { dispatch } = useCart();
  return (
    <div>
      <p>{product.name}</p>
      <button onClick={() => dispatch({ type: 'ADD_ITEM', item: product })}>
        Add to cart
      </button>
    </div>
  );
}

// CartIcon — shows count:
function CartIcon() {
  const { cart } = useCart();
  const total = cart.items.reduce((sum, i) => sum + i.qty, 0);
  return <span>Cart ({total})</span>;
}

import { render, screen, fireEvent } from '@testing-library/react';
import { CartProvider } from './CartContext';
import { ProductCard, CartIcon } from './components';

const product = { id: 1, name: 'Widget', price: 9.99 };

function TestApp() {
  return (
    <CartProvider>
      <CartIcon />
      <ProductCard product={product} />
    </CartProvider>
  );
}

test('adds item to cart and updates icon', () => {
  render(<TestApp />);
  expect(screen.getByText('Cart (0)')).toBeInTheDocument();

  fireEvent.click(screen.getByRole('button', { name: /add to cart/i }));

  expect(screen.getByText('Cart (1)')).toBeInTheDocument();
});
